#!/usr/bin/env python3
# This file was generated by Cursor AI on 2026-05-05.
"""
Build stacked histograms and scatter plots from eqsat JSON results.

Each figure uses one set of x-axis bins (percent difference vs. baseline). Plots use
``100·(run-control)/control``, so larger reductions in ``run`` (lower metric than baseline)
appear toward the negative side of the axis; stacked histogram x-axes are inverted so more
negative values lie toward the right. Each value is rounded to the
nearest whole percent before binning (sabre-total-bytes: nearest 5%); histogram bins
match that step from the minimum to the maximum rounded value present. For each bin,
bars are stacked
by run type (ilp_ac, ilp_no_ac, greedy_ac, greedy_no_ac): segment height
is how many formulas had that run type's value fall in that bin. Run JSON files
that are missing are omitted from the stack and legend. Samples where that
run type's exact difference vs. baseline is zero are omitted from the plot data before
rounding/binning.

Requires: matplotlib, numpy (``pip install matplotlib`` or use a venv).

Example:
  python3 plot_results.py \\
    --results-dir /path/to/benchmarks/scripts/eqsat/results \\
    --output-dir /path/to/out
"""

from __future__ import annotations

import argparse
import math
import json
import sys
from collections import Counter
from pathlib import Path
from typing import Any, cast

# Run-type order (bottom -> top in stacked bars)
RUN_TYPES: list[tuple[str, str, str]] = [
    ("ILP", "ilp_ac.json", "ilp-ac"),
    ("ILP No AC", "ilp_no_ac.json", "ilp-no-ac"),
    ("Greedy", "greedy_ac.json", "greedy-ac"),
    ("Greedy No AC", "greedy_no_ac.json", "greedy-no-ac"),
]

RUN_COLORS = {
    "Control": "#8A8A8A",
    "ILP": "#082A54",
    "ILP No AC": "#E02B35",
    "Greedy": "#F0C571",
    "Greedy No AC": "#59A89C",
}
RUN_MARKERS = {
    "ILP": "o",
    "ILP No AC": "s",
    "Greedy": "^",
    "Greedy No AC": "D",
}
RUN_HATCHES = {
    "ILP": "///",
    "ILP No AC": "\\\\\\",
    "Greedy": "xxx",
    "Greedy No AC": "...",
}

# For scatter plots, AC/no-AC pairs overlap; keep one representative per group.
SCATTER_RUN_LABELS = ("ILP", "ILP No AC")
SCATTER_LEGEND_LABELS = {
    "ILP": "AC",
    "ILP No AC": "No AC",
}
SCATTER_COLOR_BY_CATEGORY = {
    "AC, no timeout": "#6FA4E8",
    "AC, Gurobi timeout": "#0B3F7A",
    "No AC, no timeout": "#F29BA2",
    "No AC, Gurobi timeout": "#B21E2B",
}


def _timeout(block: dict[str, Any] | None) -> bool:
    if not block:
        return True
    es = str(block.get("egglog-status", "")).lower()
    gs = str(block.get("gurobi-status", "")).lower()
    return "timeout" in es or "timeout" in gs


def _num(x: Any) -> float | None:
    if x is None:
        return None
    if isinstance(x, (int, float)):
        if isinstance(x, float) and (x != x):  # NaN
            return None
        return float(x)
    return None


def _sample_paths(paths: set[str], *, limit: int = 8) -> str:
    """Comma-separated repr sample for error messages."""
    xs = sorted(paths)
    if len(xs) <= limit:
        return ", ".join(repr(x) for x in xs)
    head = ", ".join(repr(x) for x in xs[:limit])
    return f"{head}, ... ({len(xs) - limit} more)"


def load_results(results_dir: Path) -> tuple[list[str], list[dict[str, Any]], list[tuple[str, str, str]]]:
    """Return (filenames aligned across runs, per-row dicts, active RUN_TYPES entries).

    Rows are aligned by ``filename`` across ``control.json`` and every run-type JSON
    that exists. Missing run files are skipped with a stderr warning. Only benchmarks
    present in ``control.json`` and every loaded run file are kept (intersection).
    """
    control_path = results_dir / "control.json"
    if not control_path.is_file():
        raise FileNotFoundError(f"Missing {control_path}")

    control_rows = json.loads(control_path.read_text())["results"]
    filenames: list[str] = []
    control_by_file: dict[str, Any] = {}
    for r in control_rows:
        fn = r.get("filename")
        if not isinstance(fn, str) or not fn:
            raise ValueError("control.json: row missing non-empty filename")
        if fn in control_by_file:
            raise ValueError(f"control.json: duplicate filename {fn!r}")
        control_by_file[fn] = r["control"]
        filenames.append(fn)

    control_set = set(filenames)
    active_run_types: list[tuple[str, str, str]] = []
    by_label: dict[str, dict[str, dict[str, Any]]] = {}

    for label, json_name, nested_key in RUN_TYPES:
        path = results_dir / json_name
        if not path.is_file():
            print(
                f"Warning: missing {path}; omitting '{label}' from plots.",
                file=sys.stderr,
            )
            continue
        rows = json.loads(path.read_text())["results"]
        by_file: dict[str, dict[str, Any]] = {}
        for r in rows:
            fn = r.get("filename")
            if not isinstance(fn, str) or not fn:
                raise ValueError(f"{json_name}: row missing non-empty filename")
            if fn in by_file:
                raise ValueError(f"{json_name}: duplicate filename {fn!r}")
            block = r.get(nested_key)
            if not isinstance(block, dict):
                raise ValueError(f"{json_name} {fn!r}: missing {nested_key}")
            by_file[fn] = block

        run_set = set(by_file)
        missing_in_run = control_set - run_set
        extra_in_run = run_set - control_set
        if missing_in_run:
            print(
                f"Warning: {json_name}: {len(missing_in_run)} file(s) in control.json "
                f"missing here (using intersection for alignment): "
                f"{_sample_paths(missing_in_run)}",
                file=sys.stderr,
            )
        if extra_in_run:
            print(
                f"Warning: {json_name}: {len(extra_in_run)} file(s) not in control.json: "
                f"{_sample_paths(extra_in_run)}",
                file=sys.stderr,
            )

        active_run_types.append((label, json_name, nested_key))
        by_label[label] = by_file

    if not active_run_types:
        names = ", ".join(t[1] for t in RUN_TYPES)
        raise FileNotFoundError(
            f"No run result JSONs found under {results_dir} (need at least one of: {names})"
        )

    common: set[str] | None = None
    for label, _, _ in active_run_types:
        s = set(by_label[label])
        common = s if common is None else (common & s)

    assert common is not None
    filenames_out = [fn for fn in filenames if fn in common]
    dropped = len(filenames) - len(filenames_out)
    if dropped:
        print(
            f"Warning: excluded {dropped} control row(s) not present in every loaded run file.",
            file=sys.stderr,
        )

    per_index: list[dict[str, Any]] = []
    for fn in filenames_out:
        row: dict[str, Any] = {"filename": fn, "control": control_by_file[fn]}
        for label, _, _ in active_run_types:
            row[label] = by_label[label][fn]
        per_index.append(row)

    return filenames_out, per_index, active_run_types


def pct_diff(run_v: float, ctrl_v: float) -> float | None:
    if ctrl_v == 0.0:
        if run_v == 0.0:
            return 0.0
        return None
    return 100.0 * (run_v - ctrl_v) / ctrl_v


def collect_metric(
    per_index: list[dict[str, Any]],
    metric_key: str,
    run_types: list[tuple[str, str, str]],
    *,
    pct_step: int = 1,
) -> tuple[list[list[float]], int, int]:
    """
    Collect ``100*(run-control)/control`` per run type, rounded to the nearest ``pct_step``
    percentage points (default 1).

    Returns (one list of values per run type, in ``run_types`` order), skipped count
    (rows dropped for timeout, missing metrics, or invalid percent baseline), and
    no_point_rows (rows with valid data where every run type's exact difference vs
    control is zero, so nothing is binned). Values with exact zero difference are
    omitted before rounding per run type.
    """
    arrays: list[list[float]] = [[] for _ in run_types]
    skipped = 0
    no_point_rows = 0

    for row in per_index:
        ctrl = row["control"]
        if _timeout(ctrl):
            skipped += 1
            continue
        cv = _num(ctrl.get(metric_key))
        if cv is None:
            skipped += 1
            continue

        ok = True
        run_vals: list[float] = []
        for label, _, _ in run_types:
            blk = row[label]
            if _timeout(blk):
                ok = False
                break
            rv = _num(blk.get(metric_key))
            if rv is None:
                ok = False
                break
            run_vals.append(rv)

        if not ok:
            skipped += 1
            continue

        diffs: list[float | None] = [pct_diff(rv, cv) for rv in run_vals]
        if any(d is None for d in diffs):
            skipped += 1
            continue
        diffs_f = [cast(float, x) for x in diffs]
        row_points = 0
        for j, fd in enumerate(diffs_f):
            if fd == 0.0:
                continue
            rounded_pct = int(round(fd / float(pct_step))) * pct_step
            arrays[j].append(float(rounded_pct))
            row_points += 1
        if row_points == 0:
            no_point_rows += 1

    return arrays, skipped, no_point_rows


def collect_removed_metric(
    per_index: list[dict[str, Any]],
    metric_key: str,
    run_types: list[tuple[str, str, str]],
    *,
    round_step: int = 1,
    run_minus_control: bool = False,
) -> tuple[list[list[float]], int, int]:
    """
    Collect signed differences per run type, rounded to the nearest ``round_step`` (default 1).

    By default uses ``control-run`` (positive when the run has fewer). When
    ``run_minus_control`` is True, uses ``run-control`` instead (negative when the run has fewer,
    matching lower-is-better convention with percent ``100*(run-control)/control``).

    Returns (one list of values per run type, in ``run_types`` order), skipped count, and
    no_point_rows (valid rows where every run's rounded difference is zero so nothing
    is binned). Rows are skipped for timeout or missing metrics. Exact zero differences
    are omitted before rounding.
    """
    arrays: list[list[float]] = [[] for _ in run_types]
    skipped = 0
    no_point_rows = 0

    for row in per_index:
        ctrl = row["control"]
        if _timeout(ctrl):
            skipped += 1
            continue
        cv = _num(ctrl.get(metric_key))
        if cv is None:
            skipped += 1
            continue

        ok = True
        run_vals: list[float] = []
        for label, _, _ in run_types:
            blk = row[label]
            if _timeout(blk):
                ok = False
                break
            rv = _num(blk.get(metric_key))
            if rv is None:
                ok = False
                break
            run_vals.append(rv)

        if not ok:
            skipped += 1
            continue

        row_points = 0
        for j, rv in enumerate(run_vals):
            raw_diff = (rv - cv) if run_minus_control else (cv - rv)
            if raw_diff == 0.0:
                continue
            diff = int(round(raw_diff / float(round_step))) * round_step
            arrays[j].append(float(diff))
            row_points += 1
        if row_points == 0:
            no_point_rows += 1

    return arrays, skipped, no_point_rows


def plot_stacked_hist(
    arrays: list[list[float]],
    title: str,
    xlabel: str,
    out_path: Path,
    *,
    stack_labels: list[str],
    pct_step: int = 1,
    legend_loc: str = "upper right",
    show_legend: bool = True,
    show_ylabel: bool = False,
    y_max: int | None = None,
) -> None:
    import numpy as np
    import matplotlib

    matplotlib.use("Agg")
    import matplotlib.pyplot as plt

    matplotlib.rcParams.update(
        {
            "font.family": "serif",
            "mathtext.fontset": "dejavuserif",
            "font.size": 20,
            "hatch.linewidth": 0.5,
        }
    )

    labels = stack_labels
    colors = [RUN_COLORS[lbl] for lbl in labels]

    flat = np.concatenate([np.asarray(a, dtype=float) for a in arrays if len(a)])
    if flat.size == 0:
        print(f"Warning: no data for {title}; skipping figure.", file=sys.stderr)
        return

    rmin = int(np.min(flat))
    rmax = int(np.max(flat))
    half = pct_step / 2.0
    # One bin per pct_step from rmin through rmax inclusive.
    edges = np.arange(rmin - half, rmax + half + pct_step, float(pct_step))

    fig, ax = plt.subplots(figsize=(10, 4))
    _n, _bins, containers = ax.hist(
        arrays,
        bins=list(edges),
        stacked=True,
        label=labels,
        color=colors,
        edgecolor="white",
        linewidth=0.3,
    )
    if isinstance(containers, list):
        container_list = containers
    else:
        container_list = [containers]
    for label, container in zip(labels, container_list):
        hatch = RUN_HATCHES.get(label, "")
        patches = getattr(container, "patches", None)
        if patches is None:
            continue
        for patch in patches:
            patch.set_hatch(hatch)
    
    # Tight x limits to bin extent only (no default autoscale margin on the ends).
    ax.margins(x=0)
    ax.set_xlim(rmin - half, rmax + half)
    ax.invert_xaxis()
    if y_max is not None:
        ax.set_ylim(0, y_max)
    ax.set_xlabel(xlabel)
    if show_ylabel:
        ax.set_ylabel("Number of formulas")
    ax.grid(axis="y", linestyle="--", linewidth=0.8, alpha=0.85)
    if show_legend:
        ax.legend(loc=legend_loc, fontsize=18)
    fig.tight_layout()
    out_path.parent.mkdir(parents=True, exist_ok=True)
    fig.savefig(out_path, dpi=150, bbox_inches="tight", pad_inches=0.05)
    plt.close(fig)


def stacked_peak_count(arrays: list[list[float]]) -> int:
    """Peak stacked-bin count for one histogram."""
    flat = [x for arr in arrays for x in arr]
    if not flat:
        return 0
    counts = Counter(flat)
    return max(counts.values())


def plot_egraph_scatter(
    per_index: list[dict[str, Any]],
    out_path: Path,
    run_types: list[tuple[str, str, str]],
) -> None:
    """
    Scatter plot of num-enodes (x) vs num-eclasses (y), where color denotes:
      - AC, no timeout
      - AC, gurobi timeout
      - No AC, no timeout
      - No AC, gurobi timeout
    Virtual-best files are not included.
    """
    import matplotlib

    matplotlib.use("Agg")
    import matplotlib.pyplot as plt
    from matplotlib.lines import Line2D

    matplotlib.rcParams.update(
        {
            "font.family": "serif",
            "mathtext.fontset": "dejavuserif",
            "font.size": 20,
        }
    )

    points: list[tuple[str, str, float, float]] = []

    for row in per_index:
        for label, _, _ in run_types:
            if label not in SCATTER_RUN_LABELS:
                continue
            blk = row.get(label)
            if not isinstance(blk, dict):
                continue
            enodes = _num(blk.get("num-enodes"))
            eclasses = _num(blk.get("num-eclasses"))
            if enodes is None or eclasses is None:
                continue
            if enodes < 0.0 or eclasses < 0.0:
                continue
            gs = str(blk.get("gurobi-status", "")).lower()
            ac_group = SCATTER_LEGEND_LABELS.get(label, label)
            if ac_group == "AC":
                category = "AC, Gurobi timeout" if "timeout" in gs else "AC, no timeout"
            else:
                category = (
                    "No AC, Gurobi timeout" if "timeout" in gs else "No AC, no timeout"
                )
            filename = str(row.get("filename", "<unknown>"))
            points.append((filename, category, enodes, eclasses))

    def iqr_bounds(values: list[float]) -> tuple[float, float]:
        import numpy as np

        if not values:
            return (float("-inf"), float("inf"))
        arr = np.asarray(values, dtype=float)
        q1 = float(np.percentile(arr, 0))
        q3 = float(np.percentile(arr, 100))
        iqr = q3 - q1
        # If all values are identical (iqr==0), keep exact-value points only.
        if iqr == 0.0:
            return (q1, q3)
        k = 1.5
        return (q1 - k * iqr, q3 + k * iqr)

    all_x = [x for _, _, x, _ in points]
    all_y = [y for _, _, _, y in points]
    x_lo, x_hi = iqr_bounds(all_x)
    y_lo, y_hi = iqr_bounds(all_y)

    filtered_points = [
        (filename, category, x, y)
        for filename, category, x, y in points
        if x_lo <= x <= x_hi and y_lo <= y <= y_hi
    ]
    outlier_points = [
        (filename, category, x, y)
        for filename, category, x, y in points
        if not (x_lo <= x <= x_hi and y_lo <= y <= y_hi)
    ]

    grouped: dict[str, tuple[list[float], list[float]]] = {}
    for _filename, category, x, y in filtered_points:
        if category not in grouped:
            grouped[category] = ([], [])
        xs, ys = grouped[category]
        xs.append(x)
        ys.append(y)

    fig, ax = plt.subplots(figsize=(10, 5))
    for category, (xs, ys) in grouped.items():
        marker = "^" if "gurobi timeout" in category.lower() else "o"
        ax.scatter(
            xs,
            ys,
            s=75,
            alpha=0.8,
            c=SCATTER_COLOR_BY_CATEGORY[category],
            marker=marker,
            edgecolors="none",
        )

    ax.set_xlabel("Number of e-nodes")
    ax.set_ylabel("Number of e-classes")
    ax.set_xscale("log")
    ax.set_yscale("log")
    ax.grid(True, linestyle="--", linewidth=0.8, alpha=0.55)

    combined_handles = [
        Line2D(
            [0],
            [0],
            marker="^" if "gurobi timeout" in category.lower() else "o",
            linestyle="",
            color="none",
            label=category,
            markerfacecolor=SCATTER_COLOR_BY_CATEGORY[category],
            markersize=15,
        )
        for category in (
            "AC, no timeout",
            "AC, Gurobi timeout",
            "No AC, no timeout",
            "No AC, Gurobi timeout",
        )
    ]
    ax.legend(
        handles=combined_handles,
        loc="lower right",
        fontsize=14,
    )
    if outlier_points:
        print(
            f"Scatter outliers excluded ({len(outlier_points)} total): "
            f"bounds x=[{x_lo:.3f}, {x_hi:.3f}], y=[{y_lo:.3f}, {y_hi:.3f}]"
        )
        for filename, category, x, y in sorted(outlier_points):
            print(
                f"  OUTLIER {category}: enodes={x:.3f}, eclasses={y:.3f}, file={filename}"
            )
    else:
        print("Scatter outliers excluded: none")
    fig.tight_layout()
    out_path.parent.mkdir(parents=True, exist_ok=True)
    fig.savefig(out_path, dpi=150, bbox_inches="tight", pad_inches=0.05)
    plt.close(fig)


def plot_total_time_vs_scq_reduction_scatter(
    per_index: list[dict[str, Any]],
    out_path: Path,
    run_types: list[tuple[str, str, str]],
) -> None:
    """
    Scatter plot of total optimization time (EggLog + Gurobi) vs. exact
    percent SCQ difference ``100*(run-control)/control`` (no rounding; negative when SCQ is reduced).
    """
    import matplotlib

    matplotlib.use("Agg")
    import matplotlib.pyplot as plt
    from matplotlib.lines import Line2D

    matplotlib.rcParams.update(
        {
            "font.family": "serif",
            "mathtext.fontset": "dejavuserif",
            "font.size": 20,
        }
    )

    grouped: dict[str, tuple[list[float], list[float]]] = {
        label: ([], []) for label, _, _ in run_types
    }

    for row in per_index:
        ctrl = row.get("control")
        if not isinstance(ctrl, dict):
            continue
        ctrl_scq = _num(ctrl.get("scq"))
        if ctrl_scq is None:
            continue

        for label, _, _ in run_types:
            blk = row.get(label)
            if not isinstance(blk, dict):
                continue
            run_scq = _num(blk.get("scq"))
            if run_scq is None:
                continue
            scq_pct_diff = pct_diff(run_scq, ctrl_scq)
            if scq_pct_diff is None:
                continue

            egglog_enc = _num(blk.get("egglog-encoding-time"))
            egglog_solve = _num(blk.get("egglog-solver-time"))
            gurobi_enc = _num(blk.get("gurobi-encoding-time"))
            gurobi_solve = _num(blk.get("gurobi-solving-time"))
            if (
                egglog_enc is None
                or egglog_solve is None
                or gurobi_enc is None
                or gurobi_solve is None
            ):
                continue
            if (
                egglog_enc < 0.0
                or egglog_solve < 0.0
                or gurobi_enc < 0.0
                or gurobi_solve < 0.0
            ):
                continue

            total_time = egglog_enc + egglog_solve + gurobi_enc + gurobi_solve
            xs, ys = grouped[label]
            xs.append(total_time)
            ys.append(float(scq_pct_diff))

    fig, ax = plt.subplots(figsize=(10, 5))
    for label, (xs, ys) in grouped.items():
        if not xs:
            continue
        color = RUN_COLORS[label]
        marker = RUN_MARKERS.get(label, "o")
        ax.scatter(xs, ys, s=45, alpha=0.8, c=color, marker=marker, edgecolors="none")

    ax.set_xlabel("Total optimization time (s): EggLog + Gurobi")
    ax.set_ylabel(
        r"Percent diff. in $\mathsf{Mem}(\mathsf{DAG}(\varphi))$"
    )
    ax.set_xscale("log")
    ax.grid(True, linestyle="--", linewidth=0.8, alpha=0.55)
    ax.invert_yaxis()

    run_handles = [
        Line2D(
            [0],
            [0],
            marker=RUN_MARKERS.get(label, "o"),
            linestyle="",
            color="none",
            label=label,
            markerfacecolor=RUN_COLORS[label],
            markersize=10,
        )
        for label, _, _ in run_types
    ]
    ax.legend(handles=run_handles, loc="best", fontsize=12)

    fig.tight_layout()
    out_path.parent.mkdir(parents=True, exist_ok=True)
    fig.savefig(out_path, dpi=150, bbox_inches="tight", pad_inches=0.05)
    plt.close(fig)


def main() -> int:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument(
        "--results-dir",
        type=Path,
        default=Path(__file__).resolve().parent.parent / "results",
        help="Directory containing control.json and run JSON files",
    )
    parser.add_argument(
        "--output-dir",
        type=Path,
        default=None,
        help="Where to write PNG files (default: <results-dir>/plots)",
    )
    args = parser.parse_args()
    results_dir = args.results_dir.resolve()
    out_dir = (
        args.output_dir.resolve()
        if args.output_dir
        else results_dir / "plots"
    )

    try:
        _, per_index, run_types = load_results(results_dir)
    except (FileNotFoundError, ValueError, json.JSONDecodeError) as e:
        print(f"Error: {e}", file=sys.stderr)
        return 1

    stack_labels = [t[0] for t in run_types]
    # Histograms in the same group share y-axis max (stacked bar height).
    Y_GROUP_SCQ_SABRE = "scq_sabre"
    Y_GROUP_R2U2_INSTR = "r2u2_instr"

    jobs: list[tuple[str, str, str, str, int, str, str, bool, bool, str]] = [
        (
            "scq",
            "hist_scq_pct_vs_control.png",
            "Percent difference in SCQ vs. baseline (100·(run-control)/control)",
            r"Percent difference in $\mathsf{Mem}(\mathsf{DAG}(\varphi))$ vs. baseline",
            5,
            "pct",
            "upper right",
            True,
            True,
            Y_GROUP_SCQ_SABRE,
        ),
        (
            "num-tl-instructions",
            "hist_num_tl_instructions_pct_vs_control.png",
            "Percent difference in num-tl-instructions vs. baseline",
            r"Percent difference in # of R2U2 instructions vs. baseline",
            5,
            "pct",
            "upper right",
            False,
            True,
            Y_GROUP_R2U2_INSTR,
        ),
        (
            "num-tl-instructions",
            "hist_num_tl_instructions_removed_vs_control.png",
            "Difference vs. baseline for num-tl-instructions",
            r"Difference in # of R2U2 instructions vs. baseline",
            1,
            "removed",
            "upper right",
            False,
            False,
            Y_GROUP_R2U2_INSTR,
        ),
        (
            "sabre-total-bytes",
            "hist_sabre_total_bytes_pct_vs_control.png",
            "Percent difference in sabre-total-bytes vs. baseline, rounded to nearest 5%)",
            r"Percent difference in SABRe encoding vs. baseline",
            5,
            "pct",
            "upper left",
            False,
            False,
            Y_GROUP_SCQ_SABRE,
        ),
    ]

    prepared: list[
        tuple[list[list[float]], str, str, int, str, bool, bool, str, int, str]
    ] = []
    peak_by_y_group: dict[str, int] = {}

    for (
        metric_key,
        fname,
        title,
        xlabel,
        pct_step,
        mode,
        legend_loc,
        show_legend,
        show_ylabel,
        y_group,
    ) in jobs:
        if mode == "pct":
            arrays, skipped, no_point_rows = collect_metric(
                per_index, metric_key, run_types, pct_step=pct_step
            )
        elif mode == "removed":
            arrays, skipped, no_point_rows = collect_removed_metric(
                per_index,
                metric_key,
                run_types,
                round_step=pct_step,
                run_minus_control=(metric_key == "num-tl-instructions"),
            )
        else:
            raise ValueError(f"Unknown mode: {mode}")

        omitted_files = skipped + no_point_rows

        peak = stacked_peak_count(arrays)
        prev = peak_by_y_group.get(y_group, 0)
        peak_by_y_group[y_group] = max(prev, peak)
        prepared.append(
            (
                arrays,
                title,
                xlabel,
                pct_step,
                legend_loc,
                show_legend,
                show_ylabel,
                fname,
                omitted_files,
                y_group,
            )
        )

    y_max_by_group = {
        g: max(1, int(math.ceil(peak_by_y_group.get(g, 0) * 1.02)))
        for g in (Y_GROUP_SCQ_SABRE, Y_GROUP_R2U2_INSTR)
    }

    for (
        arrays,
        title,
        xlabel,
        pct_step,
        legend_loc,
        show_legend,
        show_ylabel,
        fname,
        omitted_files,
        y_group,
    ) in prepared:
        counts = ", ".join(
            f"{stack_labels[i]}={len(arrays[i])}" for i in range(len(run_types))
        )
        y_max = y_max_by_group[y_group]
        plot_stacked_hist(
            arrays,
            title,
            xlabel,
            out_dir / fname,
            stack_labels=stack_labels,
            pct_step=pct_step,
            legend_loc=legend_loc,
            show_legend=show_legend,
            show_ylabel=show_ylabel,
            y_max=y_max,
        )
        print(
            f"Wrote {out_dir / fname} ({counts}; "
            f"omitted_files={omitted_files}; y_group={y_group}; shared_ymax={y_max})"
        )

    scatter_path = out_dir / "scatter_enodes_vs_eclasses.png"
    plot_egraph_scatter(per_index, scatter_path, run_types)
    print(f"Wrote {scatter_path}")
    time_scq_scatter_path = out_dir / "scatter_total_time_vs_scq_reduction.png"
    plot_total_time_vs_scq_reduction_scatter(per_index, time_scq_scatter_path, run_types)
    print(f"Wrote {time_scq_scatter_path}")

    return 0


if __name__ == "__main__":
    raise SystemExit(main())